import React, { useState, useEffect } from "react";
import { endpoint } from "../Config";
import "./FileManager.css";
import { ToastContainer, toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import CodeMirror from "@uiw/react-codemirror";
import { json } from "@codemirror/lang-json";
import { StreamLanguage } from "@codemirror/language";
import { shell } from "@codemirror/legacy-modes/mode/shell";

// Icons
import FileIcon from "../assets/icons/document.png";
import OpenDirectoryIcon from "../assets/icons/open-folder.png";
import ClosedDirectoryIcon from "../assets/icons/folder.png";

// Modal Component
const Modal = ({ isOpen, onClose, onSubmit, title, placeholder1, showSecondInput, placeholder2, isFileInput }) => {
  const [input1, setInput1] = useState("");
  const [input2, setInput2] = useState("");

  const handleFileChange = (event) => {
    setInput1(event.target.files[0]);
  };

  const handleSubmit = () => {
    onSubmit(input1, input2);
    setInput1("");
    setInput2("");
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="modal-overlay">
      <div className="modal-content">
        <h3>{title}</h3>
        {isFileInput ? (
          <input
            type="file"
            accept={title === "Upload Directory (ZIP)" ? ".zip" : undefined}
            onChange={handleFileChange}
            className="styled-input"
          />
        ) : (
          <input
            type="text"
            placeholder={placeholder1}
            value={input1}
            onChange={(e) => setInput1(e.target.value)}
            className="styled-input"
          />
        )}
        {showSecondInput && (
          <input
            type="text"
            placeholder={placeholder2}
            value={input2}
            onChange={(e) => setInput2(e.target.value)}
            className="styled-input"
          />
        )}
        <div className="modal-buttons">
          <button onClick={handleSubmit} className="confirm-button">
            Submit
          </button>
          <button onClick={onClose} className="cancel-button">
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
};

// FileTree and FileTreeNode Components
const getDirectoryIcon = (isExpanded) => (
  <img
    src={isExpanded ? OpenDirectoryIcon : ClosedDirectoryIcon}
    alt={isExpanded ? "Open Directory" : "Closed Directory"}
    className="icon-size"
  />
);

const FileTree = ({ fileTree, onFileSelect }) => (
  <ul className="file-tree">
    {fileTree.map((node) => (
      <FileTreeNode key={node.path} node={node} onFileSelect={onFileSelect} />
    ))}
  </ul>
);

const FileTreeNode = ({ node, onFileSelect }) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const handleToggle = () => {
    if (node.type === "directory") {
      setIsExpanded(!isExpanded);
    } else {
      onFileSelect(node);
    }
  };

  return (
    <>
      <li
        className={`file-entry flex items-center justify-between px-4 py-2 rounded-lg hover:bg-gray-100 cursor-pointer ${
          node.type === "directory" ? "bg-yellow-50" : "bg-blue-50"
        }`}
        onClick={handleToggle}
      >
        <div className="flex items-center gap-4">
          <span>
            {node.type === "directory" ? getDirectoryIcon(isExpanded) : <img src={FileIcon} alt="File Icon" className="icon-size" />}
          </span>
          <span className="text-sm font-medium text-gray-800">{node.name}</span>
        </div>
        {node.type === "directory" && (
          <span
            className={`dropdown-arrow ${
              isExpanded ? "arrow-down" : "arrow-right"
            }`}
          >
            ▶
          </span>
        )}
      </li>
      {node.type === "directory" && isExpanded && node.children?.length > 0 && (
        <ul className="pl-6 border-l-2 border-gray-200">
          {node.children.map((child) => (
            <FileTreeNode key={child.path} node={child} onFileSelect={onFileSelect} />
          ))}
        </ul>
      )}
    </>
  );
};

// FileManager Component
const FileManager = () => {
  const [fileTree, setFileTree] = useState([]);
  const [fileContent, setFileContent] = useState("");
  const [loading, setLoading] = useState(false);
  const [selectedFilePath, setSelectedFilePath] = useState("");

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalAction, setModalAction] = useState("");

  // Cache for file contents
  const [fileCache, setFileCache] = useState({});

  useEffect(() => {
    fetchFileTree();
  }, []);

  const fetchFileTree = async () => {
    setLoading(true);
    try {
      const response = await fetch(`${endpoint}/file-tree`, { method: "POST" });
      if (response.ok) {
        const data = await response.json();
        setFileTree(data);
      } else {
        throw new Error("Failed to fetch file tree.");
      }
    } catch (error) {
      toast.error(error.message);
    } finally {
      setLoading(false);
    }
  };

  const fetchFileContent = async (filePath) => {
    // Check if the file content is already in the cache
    if (fileCache[filePath]) {
      setFileContent(fileCache[filePath]);
      return;
    }

    setLoading(true);
    try {
      const response = await fetch(`${endpoint}/read-file`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: filePath }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail || "Error fetching file content.");
      }

      const data = await response.json();
      const content = data.content || "";

      // Update the cache with the new content
      setFileCache(prevCache => ({ ...prevCache, [filePath]: content }));
      setFileContent(content);
    } catch (error) {
      toast.error(error.message);
    } finally {
      setLoading(false);
    }
  };

  const handleFileClick = (node) => {
    if (node.type === "file") {
      setSelectedFilePath(node.path);
      fetchFileContent(node.path);
    } else {
      setSelectedFilePath("");
    }
  };

  const handleAction = async (action, payload = {}) => {
    try {
      let url, body;

      switch (action) {
        case "createDir":
          url = `${endpoint}/create-dir`;
          body = JSON.stringify({ name: payload.name });
          break;
        case "createFile":
          url = `${endpoint}/create-file`;
          body = JSON.stringify({ name: payload.name });
          break;
        case "rename":
          url = `${endpoint}/rename-file-dir`;
          body = JSON.stringify({ old_name: payload.oldName, new_name: payload.newName });
          break;
        case "delete":
          url = `${endpoint}/delete-file-dir`;
          body = JSON.stringify({ name: payload.name });
          break;
        case "save":
          url = `${endpoint}/write-file`;
          body = JSON.stringify({ name: selectedFilePath, content: fileContent });
          break;

        case "generateKey":
            url = `${endpoint}/key-gen`;
            body = JSON.stringify({ key_name: payload.name });
            break;
        case "uploadFile":
          url = `${endpoint}/upload-file`;
          const formDataFile = new FormData();
          formDataFile.append("file", payload);
          const responseFile = await fetch(url, {
            method: "POST",
            body: formDataFile,
          });

          if (!responseFile.ok) {
            const errorData = await responseFile.json();
            throw new Error(errorData.detail || "File upload failed.");
          }

          const responseDataFile = await responseFile.json();
          toast.success(responseDataFile.message);
          fetchFileTree();
          return;

        case "uploadDir":
          url = `${endpoint}/upload-dir`;
          const formDataDir = new FormData();
          formDataDir.append("file", payload); // Add zip file to form data
          const responseDir = await fetch(url, {
            method: "POST",
            body: formDataDir,
          });

          if (!responseDir.ok) {
            const errorData = await responseDir.json();
            throw new Error(errorData.detail || "Directory upload failed.");
          }

          const responseDataDir = await responseDir.json();
          toast.success(responseDataDir.message);
          fetchFileTree();
          return;

        default:
          throw new Error("Invalid action");
      }

      const response = await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body,
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail || "Action failed.");
      }

      if (action !== "save") fetchFileTree();
      toast.success(`${action} successful.`);
    } catch (error) {
      toast.error(error.message);
    }
  };

  const executeModalAction = (input1, input2) => {
    if (modalAction === "rename") {
      handleAction("rename", { oldName: input1, newName: input2 });
    } else if (modalAction === "generateKey") {
      handleAction("generateKey", { name: input1 });
    } else if (modalAction === "uploadFile" || modalAction === "uploadDir") {
      handleAction(modalAction, input1);
    } else {
      handleAction(modalAction, { name: input1 });
    }
    setIsModalOpen(false);
    setModalAction("");
  };

  const getEditorExtensions = () => {
    if (!selectedFilePath) return [];

    const extension = selectedFilePath.split(".").pop()?.toLowerCase();
    switch (extension) {
      case "json":
        return [json()];
      case "sh":
      case "bash":
        return [StreamLanguage.define(shell)];
      case "txt":
      default:
        return [];
    }
  };

  const editorConfig = {
    theme: "light",
    height: "500px",
    style: { fontSize: "14px" },
    basicSetup: true,
  };

  const handleEditorChange = (value) => {
    setFileContent(value);

    // Update the file cache when the content changes
    if (selectedFilePath) {
      setFileCache((prevCache) => ({
        ...prevCache,
        [selectedFilePath]: value, // Update cache with new content
      }));
    }
  };

  return (
    <div id="app">
      <ToastContainer position="bottom-right" autoClose={3000} closeButton={false} />
      {loading && <p>Loading...</p>}

      <div id="file-tree-container">
        <h4>File Tree</h4>
        <FileTree fileTree={fileTree} onFileSelect={handleFileClick} />
      </div>

      <div id="file-content-container">
        <div className="file-content-header flex items-center gap-4">
          <div className="FileSave">
            <h4>{selectedFilePath || "File Content"}</h4>
            <button
              className="save-button short-button"
              onClick={() => handleAction("save")}
              disabled={!selectedFilePath || !fileContent}
            >
              Save
            </button>
          </div>

          <div className="header-buttons">
            <select
              className="action-select"
              value=""
              onChange={(e) => {
                const action = e.target.value;
                if (action === "uploadFile" || action === "uploadDir") {
                  setModalAction(action);
                  setIsModalOpen(true);
                } else if (action) {
                  setModalAction(action);
                  setIsModalOpen(true);
                }
              }}
            >
              <option value="" disabled>
                Select an action
              </option>
              <option value="createDir">Create Directory</option>
              <option value="createFile">Create File</option>
              <option value="rename">Rename</option>
              <option value="delete">Delete</option>
              <option value="generateKey">Generate Key</option>
              <option value="uploadFile">Upload File</option>
              <option value="uploadDir">Upload Directory (ZIP)</option>
            </select>
          </div>
        </div>

        <div className="file-editor">
          <CodeMirror
            value={fileContent || ''}
            height={editorConfig.height}
            theme={editorConfig.theme}
            style={editorConfig.style}
            extensions={getEditorExtensions()}
            basicSetup={editorConfig.basicSetup}
            onChange={(value) => handleEditorChange(value)}
            className="editor-wrapper"
          />
        </div>
      </div>

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSubmit={executeModalAction}
        title={
          modalAction === "rename"
            ? "Rename File/Directory"
            : modalAction === "generateKey"
            ? "Generate Key"
            : modalAction === "uploadFile"
            ? "Upload File"
            : modalAction === "uploadDir"
            ? "Upload Directory (ZIP)"
            : `Enter Details for ${modalAction}`
        }
        placeholder1={
          modalAction === "rename"
            ? "Enter current name"
            : modalAction === "generateKey"
            ? "Enter key name"
            : modalAction === "uploadFile" || modalAction === "uploadDir"
            ? "Choose file"
            : "Enter name"
        }
        placeholder2={modalAction === "rename" ? "Enter new name" : ""}
        showSecondInput={modalAction === "rename"}
        isFileInput={modalAction === "uploadFile" || modalAction === "uploadDir"}
      />
    </div>
  );
};

export default FileManager;
