import React, { useState, useEffect } from "react";
import { useParams } from "react-router-dom"; // Import useParams
import { endpoint } from "../Config"; // Ensure that endpoint is imported from Config
import "./JobDetails.css";

const JobDetails = () => {
  const { jobId } = useParams(); // Get the jobId from the route parameter
  const [jobDetails, setJobDetails] = useState(null);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    // Fetch job details using the jobId
    const fetchJobDetails = async () => {
      try {
        const response = await fetch(`${endpoint}/job-details`, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({ jobId }),
        });

        if (!response.ok) {
          throw new Error("Failed to fetch job details");
        }

        const data = await response.json();
        setJobDetails(data);
      } catch (error) {
        console.error("Error fetching job details:", error);
      }
    };

    fetchJobDetails();
  }, [jobId]); // Re-fetch if the jobId changes

  const copyToClipboard = (text) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000); // Reset after 2 seconds
  };

  if (!jobDetails) {
    return <div>Loading job details...</div>;
  }

  return (
    <div className="job-details-container">
      <h3>Job Details</h3>
      <hr></hr>
      <div className="Detail-Section-Container">
        <div className="detail-section">
          <span className="detail-label">Job ID:</span>
          <span className="detail-value">{jobId}</span>
        </div>

        <div className="detail-section">
          <span className="detail-label">Workflow:</span>
          <span className="detail-value">{jobDetails.workflow}</span>
        </div>

        <div className="detail-section">
          <span className="detail-label">Status:</span>
          <span className="detail-value">{jobDetails.status}</span>
        </div>

        <div className="detail-section">
          <span className="detail-label">Timestamp:</span>
          <span className="detail-value">
            {new Date(jobDetails.timestamp).toLocaleString()}
          </span>
        </div>

        <div className="detail-section">
          <span className="detail-label">Auth Config:</span>
          <span className="detail-value">{jobDetails.auth_config}</span>
        </div>

        <div className="detail-section">
          <span className="detail-label">PID:</span>
          <span className="detail-value">{jobDetails.pid}</span>
        </div>
      </div>
      {/* Display job result if the job is completed */}
      {jobDetails.status === "Completed" && (
        <div className="job-result">
          <div className="copy-btn-container">
            <button
              className={`copy-btn ${copied ? "copied" : ""}`}
              onClick={() => copyToClipboard(jobDetails.output)}
            >
              {copied ? "✔" : "📋"}
            </button>
          </div>
          <pre className="job-output">{jobDetails.output}</pre>
        </div>
      )}
    </div>
  );
};

export default JobDetails;
