import React, { useState } from "react";
import { Link, useLocation } from "react-router-dom";
import "./Header.css";
import logo from "./assets/hb_logo.png";


const Header = () => {
  const location = useLocation();
  const currentPath = location.pathname;
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const toggleMenu = () => {
    setIsMenuOpen((prev) => !prev);
  };

  return (
    <header className="header">
      <nav className="navbar">
        <Link className="navbar-brand" to="/" style={{ display: 'flex', alignItems: 'center' }}>
          <img src={logo} alt="Website Logo" className="logo" /> {/* Website logo */}
          <div className="separator" />
          <span className="system-controller">Systems Controller</span>
        </Link>
        <button className="menu-toggle" onClick={toggleMenu} aria-label="Toggle menu">
          ☰
        </button>
        <ul className={`nav ${isMenuOpen ? "open" : ""}`}>
          <li>
            <Link
              to="/workspace"
              className={`nav-link ${currentPath === "/workspace" ? "active" : ""}`}
              aria-current={currentPath === "/workspace" ? "page" : undefined}
            >
              Workspace
            </Link>
          </li>
          <li>
            <Link
              to="/exec"
              className={`nav-link ${currentPath === "/exec" ? "active" : ""}`}
              aria-current={currentPath === "/exec" ? "page" : undefined}
            >
              Exec
            </Link>
          </li>
          <li>
            <Link
              to="/jobs"
              className={`nav-link ${currentPath === "/jobs" ? "active" : ""}`}
              aria-current={currentPath === "/jobs" ? "page" : undefined}
            >
              Jobs
            </Link>
          </li>
          <li>
            <Link
              to="/services"
              className={`nav-link ${currentPath === "/services" ? "active" : ""}`}
              aria-current={currentPath === "/services" ? "page" : undefined}
            >
              Services
            </Link>
          </li>
        </ul>
      </nav>
    </header>
  );
};

export default Header;