// Services.js
import React, { useState, useEffect, useMemo } from "react";
import { endpoint } from "../Config";
import { FaSyncAlt } from "react-icons/fa"; // Refresh icon
import { toast, ToastContainer } from "react-toastify"; // Toast notifications
import "react-toastify/dist/ReactToastify.css"; // Toast styles
import "./Services.css"; // Custom styles
import {
  GreenCheck,
  RedXMark,
  GreyDots,
  GreyXMark,
} from "./StatusIcons"; // Status icons
import ServiceStatusModal from "./ServiceStatusModal"; // Import the Modal component

const Services = () => {
  const [authConfigs, setAuthConfigs] = useState([]);
  const [selectedAuthConfig, setSelectedAuthConfig] = useState("");
  const [services, setServices] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedServices, setSelectedServices] = useState([]);
  const [sortConfig, setSortConfig] = useState({
    key: null,
    direction: "ascending",
  });

  // Modal state
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalData, setModalData] = useState({
    serviceName: "",
    output: "",
    error: "",
  });

  useEffect(() => {
    fetchAuthConfigs();
  }, []);

  // Toast options for consistent styling
  const toastOptions = {
    position: "bottom-right",
    autoClose: 3000,
    hideProgressBar: false,
    closeOnClick: true,
    pauseOnHover: true,
    draggable: true,
    progress: undefined,
    theme: "dark",
  };

  // Helper function to generate unique service IDs
  const generateServiceId = (authConfig, nodeRef, serviceName) => {
    return `${authConfig.host}-${nodeRef}-${serviceName}`;
  };

  // Function to map backend status messages to UI-friendly statuses
  const mapStatusMessageToStatus = (message) => {
    if (typeof message !== "string") return null;

    const lowerCaseMessage = message.toLowerCase();

    if (
      lowerCaseMessage.includes("started") ||
      lowerCaseMessage.includes("running")
    ) {
      return "running";
    } else if (
      lowerCaseMessage.includes("stopped") ||
      lowerCaseMessage.includes("dead")
    ) {
      return "dead";
    } else if (lowerCaseMessage.includes("failed")) {
      return "failed";
    } else if (lowerCaseMessage.includes("restarted")) {
      return "restarting";
    } else {
      // Add more mappings as needed
      return "unknown"; // Default to 'unknown' if no match
    }
  };

  // Fetch authentication configurations
  const fetchAuthConfigs = async () => {
    try {
      const response = await fetch(`${endpoint}/auth-configs`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
      });

      if (!response.ok) {
        throw new Error(`Error: ${response.status} - ${response.statusText}`);
      }

      const data = await response.json();
      setAuthConfigs(data.auth_configs);
    } catch (error) {
      toast.error("Failed to fetch authentication configurations.", toastOptions);
      console.error("Error fetching auth configs:", error);
    }
  };

  // Fetch nodes and their services based on selected authConfig
  const fetchNodesandServicesFromAuthConfig = async (authConfig) => {
    setLoading(true);
    console.log("Auth Configs:", authConfigs);
    console.log("Selected Auth Config:", authConfig);
    const test = authConfigs.includes(authConfig);
    console.log("Auth Config Exists:", test);

    try {
      const response = await fetch(`${endpoint}/load-nodes`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ auth_config: authConfig }),
      });

      if (!response.ok) {
        throw new Error(`Failed to fetch nodes for auth_config: ${authConfig}`);
      }

      const nodeData = await response.json();

      const allServices = []; // Initialize services array
      for (const nodeRef of nodeData) {
        try {
          const serviceResponse = await fetch(`${endpoint}/list-node-services`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              auth_config: authConfig,
              node_ref: nodeRef.node_ref,
            }),
          });

          if (!serviceResponse.ok) {
            throw new Error(
              `Failed to fetch services for node_ref: ${nodeRef.node_ref}`
            );
          }

          const data = await serviceResponse.json();
          const servicesArray = Object.keys(data.services).map((key) => ({
            id: generateServiceId(authConfig, nodeRef.node_ref, key),
            node_ref: nodeRef.node_ref,
            auth_config: authConfig,
            name: key,
            ...data.services[key],
          }));

          allServices.push(...servicesArray);
        } catch (serviceError) {
          toast.error(
            `Error fetching services for node ${nodeRef.node_ref}: ${serviceError.message}`,
            toastOptions
          );
          console.error("Error fetching services:", serviceError);
        }
      }
      setServices(allServices);
    } catch (error) {
      toast.error(`Error fetching nodes: ${error.message}`, toastOptions);
      console.error("Error fetching nodes:", error);
    } finally {
      setLoading(false);
    }
  };

  const sortedServices = useMemo(() => {
    let sortableServices = [...services];
    if (sortConfig.key !== null) {
      sortableServices.sort((a, b) => {
        let aKey = a[sortConfig.key];
        let bKey = b[sortConfig.key];

        // Handle nested properties like process.status
        if (sortConfig.key.includes(".")) {
          const keys = sortConfig.key.split(".");
          aKey = keys.reduce((acc, key) => (acc ? acc[key] : undefined), a);
          bKey = keys.reduce((acc, key) => (acc ? acc[key] : undefined), b);
        }

        // Handle null or undefined values
        const aIsNull = aKey === null || aKey === undefined;
        const bIsNull = bKey === null || bKey === undefined;

        // If both are null, consider them equal
        if (aIsNull && bIsNull) return 0;

        // Decide where to place nulls
        if (aIsNull) return 1; // Push a to the end
        if (bIsNull) return -1; // Push b to the end

        // If both are strings, convert to lowercase for case-insensitive comparison
        if (typeof aKey === "string") {
          aKey = aKey.toLowerCase();
        }
        if (typeof bKey === "string") {
          bKey = bKey.toLowerCase();
        }

        if (aKey < bKey) {
          return sortConfig.direction === "ascending" ? -1 : 1;
        }
        if (aKey > bKey) {
          return sortConfig.direction === "ascending" ? 1 : -1;
        }
        return 0;
      });
    }
    return sortableServices;
  }, [services, sortConfig]);

  const requestSort = (key) => {
    let direction = "ascending";
    if (sortConfig.key === key && sortConfig.direction === "ascending") {
      direction = "descending";
    }
    setSortConfig({ key, direction });
  };

  // Handle individual service actions (start, stop, restart)
  const handleServiceAction = async (serviceName, action, nodeRef, authConfig) => {
    try {
      // Perform the actual action
      const response = await fetch(`${endpoint}/manage-node-service`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          auth_config: authConfig, // Use auth_config from service
          node_ref: nodeRef,
          service_name: serviceName,
          action: action,
        }),
      });

      if (!response.ok) {
        throw new Error(`Failed to ${action} service ${serviceName}`);
      }

      const updatedService = await response.json();
      console.log(`Full response for service ${serviceName}:`, updatedService);

      const statusMessage = updatedService.result?.status;
      console.log(
        `Extracted status message for service ${serviceName}:`,
        statusMessage
      );

      if (!statusMessage) {
        throw new Error(
          `No status message found in response for service ${serviceName}`
        );
      }

      const newStatus = mapStatusMessageToStatus(statusMessage);
      if (!newStatus) {
        throw new Error(
          `Unable to map status message to a valid status for service ${serviceName}`
        );
      }

      const serviceId = generateServiceId(authConfig, nodeRef, serviceName);

      // Update the service status based on the server response
      setServices((prevServices) =>
        prevServices.map((s) =>
          s.id === serviceId
            ? { ...s, process: { ...s.process, status: newStatus } }
            : s
        )
      );

      return newStatus;
    } catch (error) {
      // Show an error toast
      toast.error(
        `Error performing action on service ${serviceName}: ${error.message}`,
        toastOptions
      );
      console.error(`Error managing service ${serviceName}:`, error);
      return undefined; // Return undefined to indicate failure
    }
  };

  // Handle selected actions with pre-action checks
  const handleBulkAction = async (action) => {
    if (!action || selectedServices.length === 0) return;

    // Determine which selected services need the action
    const servicesToActUpon = services.filter((service) => {
      const isSelected = selectedServices.includes(service.id);
      const currentStatus = service.status || service.process.status;

      if (!isSelected) return false; // Skip services not selected
      if (action === "start" && currentStatus === "running") return false;
      if (action === "stop" && currentStatus === "dead") return false;
      if (action === "restart" && currentStatus === "dead") return false;
      return true;
    });

    if (servicesToActUpon.length === 0) {
      toast.info(
        `No selected services require the "${action}" action.`,
        toastOptions
      );
      setSelectedServices([]); // Uncheck all selected services
      return;
    }

    // Debugging: Log services to act upon
    console.log(
      `Bulk Action: ${action} on services:`,
      servicesToActUpon.map((s) => s.id)
    );

    try {
      // Create an array of promises for each service action
      const actionPromises = servicesToActUpon.map((service) =>
        handleServiceAction(
          service.name,
          action,
          service.node_ref,
          service.auth_config
        )
      );

      // Await all actions
      const updatedStatuses = await Promise.all(actionPromises);

      // Collect successful updates
      const successfulUpdates = updatedStatuses
        .map((status, index) =>
          status
            ? { id: servicesToActUpon[index].id, status }
            : null
        )
        .filter((update) => update !== null);

      // Optionally, handle failed updates here if needed

      // Show a success toast
      toast.success(
        `${successfulUpdates.length} "${action}" actions have successfully executed on selected services.`,
        toastOptions
      );
    } catch (error) {
      toast.error(
        `Bulk action "${action}" failed: ${error.message}`,
        toastOptions
      );
      console.error(`Bulk action "${action}" failed:`, error);
    } finally {
      setSelectedServices([]); // Uncheck all selected services after bulk action
    }
  };

  // Handle individual service selection
  const handleServiceSelection = (e, serviceId) => {
    if (e.target.checked) {
      setSelectedServices((prev) => [...prev, serviceId]);
    } else {
      setSelectedServices((prev) =>
        prev.filter((id) => id !== serviceId)
      );
    }
  };

  // Function to render status icons
  const renderStatusIcon = (status) => {
    switch (status) {
      case "running":
        return (
          <div className="status-container running">
            <GreenCheck aria-label="Running" />
            <span className="status-text">Running</span>
          </div>
        );
      case "failed":
        return (
          <div className="status-container failed">
            <RedXMark aria-label="Failed" />
            <span className="status-text">Failed</span>
          </div>
        );
      case "stopping":
      case "starting":
      case "restarting":
        return (
          <div className="status-container pending">
            <GreyDots
              aria-label={status.charAt(0).toUpperCase() + status.slice(1)}
            />
            <span className="status-text">
              {status.charAt(0).toUpperCase() + status.slice(1)}
            </span>
          </div>
        );
      case "dead":
        return (
          <div className="status-container dead">
            <GreyXMark aria-label="Dead" />
            <span className="status-text">Dead</span>
          </div>
        );
      default:
        return (
          <div className="status-container unknown">
            <GreyXMark aria-label="Unknown" />
            <span className="status-text">Unknown</span>
          </div>
        );
    }
  };

  // Function to handle viewing service status (stdout/stderr)
  const handleViewStatus = async (service) => {
    try {
      const response = await fetch(`${endpoint}/manage-node-service`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          auth_config: service.auth_config,
          node_ref: service.node_ref,
          service_name: service.name,
          action: "status",
        }),
      });

      if (!response.ok) {
        throw new Error(`Failed to fetch status for service ${service.name}`);
      }

      const data = await response.json();
      console.log("API Response:", data); // For debugging

      // Safely access nested fields with optional chaining
      const output = data.result?.stdout || "No output available.";
      const error = data.result?.stderr || "No error messages.";

      setModalData({
        serviceName: service.name,
        output,
        error,
      });
      setIsModalOpen(true);
    } catch (error) {
      toast.error(
        `Error fetching status for service ${service.name}: ${error.message}`,
        toastOptions
      );
      console.error("Error fetching service status:", error);
    }
  };

  // Bulk Actions Component
  const BulkActions = () => {
    const [bulkAction, setBulkAction] = useState("");

    const handleBulkActionChange = (e) => {
      setBulkAction(e.target.value);
    };

    const handleBulkActionSubmit = async () => {
      if (bulkAction && selectedServices.length > 0) {
        await handleBulkAction(bulkAction);
        setBulkAction(""); // Reset the bulk action dropdown after submission
      }
    };

    return (
      <div className="bulk-actions-container">
        <label htmlFor="bulk-action-select" className="visually-hidden">
          Select Bulk Action
        </label>
        <select
          id="bulk-action-select"
          value={bulkAction}
          onChange={handleBulkActionChange}
          aria-label="Select bulk action"
        >
          <option value="">-- Bulk Actions --</option>
          <option value="start">Start</option>
          <option value="stop">Stop</option>
          <option value="restart">Restart</option>
        </select>
        <button
          onClick={handleBulkActionSubmit}
          disabled={!bulkAction || selectedServices.length === 0 || loading}
          aria-label={`Execute bulk action ${bulkAction}`}
        >
          Execute Bulk Action
        </button>
      </div>
    );
  };

  // Table Header Component with Indeterminate State
  const TableHeader = ({
    headers,
    requestSort,
    sortConfig,
    selectedServices,
    setSelectedServices,
    services,
  }) => {
    const masterCheckboxRef = React.useRef();

    useEffect(() => {
      if (
        selectedServices.length > 0 &&
        selectedServices.length < services.length
      ) {
        masterCheckboxRef.current.indeterminate = true;
      } else {
        masterCheckboxRef.current.indeterminate = false;
      }
    }, [selectedServices, services]);

    const handleMasterCheckboxChange = (e) => {
      if (e.target.checked) {
        const allIds = services.map((service) => service.id);
        setSelectedServices(allIds);
      } else {
        setSelectedServices([]);
      }
    };

    return (
      <thead>
        <tr>
          <th>
            <input
              type="checkbox"
              ref={masterCheckboxRef}
              aria-label="Select all services"
              onChange={handleMasterCheckboxChange}
              checked={
                selectedServices.length === services.length &&
                services.length > 0
              }
            />
          </th>
          {headers.map((header) => (
            <th
              key={header.key}
              onClick={header.sortKey ? () => requestSort(header.sortKey) : undefined}
              style={{ cursor: header.sortKey ? "pointer" : "default" }}
              aria-sort={
                sortConfig.key === header.sortKey
                  ? sortConfig.direction === "ascending"
                    ? "ascending"
                    : "descending"
                  : "none"
              }
            >
              {header.label}{" "}
              {header.sortKey && sortConfig.key === header.sortKey ? (
                sortConfig.direction === "ascending" ? (
                  "↑"
                ) : (
                  "↓"
                )
              ) : (
                ""
              )}
            </th>
          ))}
        </tr>
      </thead>
    );
  };

  // Define table headers configuration
  const tableHeaders = [
    { key: "node_ref", label: "Node Reference", sortKey: "node_ref" },
    { key: "name", label: "Service Name", sortKey: "name" },
    { key: "command", label: "Command", sortKey: "command" },
    { key: "time_launched", label: "Time Launched", sortKey: "time_launched" },
    { key: "view", label: "Stdout", sortKey: null }, // Added "View" before "Status" with no sortKey
    { key: "process.status", label: "Status", sortKey: "process.status" },
  ];

  // Service Item Component
  const ServiceItem = ({ service }) => {
    return (
      <tr>
        <td>
          <input
            type="checkbox"
            aria-label={`Select service ${service.name}`}
            checked={selectedServices.includes(service.id)}
            onChange={(e) => handleServiceSelection(e, service.id)}
          />
        </td>
        <td>{service.node_ref}</td>
        <td>{service.name}</td>
        <td>{service.command}</td>
        <td>{service.time_launched}</td>
        <td>
          <button
            onClick={() => handleViewStatus(service)}
            className="view-button" // Optional: Rename class for clarity
            aria-label={`View status for service ${service.name}`}
          >
            View
          </button>
        </td>
        <td>{renderStatusIcon(service.status || service.process.status)}</td> {/* Status is now the last column */}
      </tr>
    );
  };

  // ServiceList Component
  const ServiceList = () => {
    return (
      <div className="services-list">
        <div className="services-header">
          <h3>Services for Auth Config: {selectedAuthConfig}</h3>
          <button
            onClick={() => fetchNodesandServicesFromAuthConfig(selectedAuthConfig)}
            className={`refresh-button ${loading ? 'loading' : ''}`}
            title="Refresh Services"
            aria-label="Refresh services list"
            disabled={loading}
          >
            <FaSyncAlt />
          </button>
        </div>
        {loading ? (
          <div className="loading-container">
            <p>Loading services...</p>
          </div>
        ) : (
          <div className="services-table-container">
            <table className="services-table">
              <TableHeader
                headers={tableHeaders}
                requestSort={requestSort}
                sortConfig={sortConfig}
                selectedServices={selectedServices}
                setSelectedServices={setSelectedServices}
                services={sortedServices}
              />
              <tbody>
                {sortedServices.length > 0 ? (
                  sortedServices.map((service) => (
                    <ServiceItem key={service.id} service={service} />
                  ))
                ) : (
                  <tr>
                    <td colSpan="7">No services available</td> {/* Updated colSpan */}
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        )}
        {!loading && sortedServices.length > 0 && <BulkActions />}
      </div>
    );
  };

  // Handle Auth Config change
  const handleAuthConfigChange = async (e) => {
    const selectedConfig = e.target.value;
    setSelectedAuthConfig(selectedConfig);
    toast.success(`Auth Config: "${selectedConfig}"`, toastOptions);

    if (!selectedConfig) {
      setServices([]);
      setSelectedServices([]); // Clear selected services
      return;
    }

    await fetchNodesandServicesFromAuthConfig(selectedConfig);
  };

  return (
    <div className="container">

    <div id="services-header">
      <h3>Service Management</h3>
    </div>

    <hr />

    <div className="services-container">
      <ToastContainer
        position="bottom-right"
        autoClose={3000}
        hideProgressBar={false}
        newestOnTop={false}
        closeOnClick
        rtl={false}
        pauseOnFocusLoss
        draggable
        pauseOnHover
        className="custom-toast-container"
        toastClassName="custom-toast"
      />

      <div className="dropdown-container">
        <label htmlFor="authConfig">Select Auth Config:</label>
        <select
          id="authConfig"
          value={selectedAuthConfig}
          onChange={handleAuthConfigChange}
        >
          <option value="">-- Select Auth Config --</option>
          {authConfigs.map((config, index) => (
            <option key={index} value={config}>
              {config}
            </option>
          ))}
        </select>
      </div>

      {/* Display ServiceList only if an Auth Config is selected */}
      {selectedAuthConfig && <ServiceList />}

      {/* Modal for viewing service stdout/stderr */}
      <ServiceStatusModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        serviceName={modalData.serviceName}
        output={modalData.output}
        error={modalData.error}
      />

      {/* Show message when no Auth Config is selected */}
      {!selectedAuthConfig && !loading && (
        <p>Please select an Auth Config to view services.</p>
      )}
    </div>
    </div>
  );
};

export default Services;
