

import React, { useState, useEffect } from "react";
import { endpoint } from "../Config";
import { FaExternalLinkAlt } from "react-icons/fa";
import "./Execute.css";

const Execute = () => {
  const [authConfigs, setAuthConfigs] = useState([]);
  const [workflows, setWorkflows] = useState([]);
  const [authConfig, setAuthConfig] = useState("");
  const [workflow, setWorkflow] = useState("");
  const [asJson, setAsJson] = useState(false);
  const [responseOutput, setResponseOutput] = useState("");
  const [jobId, setJobId] = useState("");
  const [jobSubmitted, setJobSubmitted] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [authConfigsResponse, workflowsResponse] = await Promise.all([
          fetch(`${endpoint}/auth-configs`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
          }),
          fetch(`${endpoint}/workflows`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
          }),
        ]);

        if (!authConfigsResponse.ok || !workflowsResponse.ok) {
          throw new Error("Failed to fetch directory entries");
        }

        const authConfigsData = await authConfigsResponse.json();
        const workflowsData = await workflowsResponse.json();

        setAuthConfigs(authConfigsData.auth_configs);
        setWorkflows(workflowsData.workflows);
      } catch (error) {
        console.error("Error loading directory entries:", error);
      }
    };

    fetchData();
  }, []);

  const handleSubmit = async (event) => {
    event.preventDefault();

    try {
      const response = await fetch(`${endpoint}/submit-job`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          auth_config: authConfig,
          workflow: workflow,
          params: { as_json: asJson },
        }),
      });

      if (!response.ok) {
        throw new Error(`Error: ${response.status} - ${response.statusText}`);
      }

      const data = await response.json();
      setResponseOutput(
        `<strong>Response:</strong><pre>${JSON.stringify(data, null, 2)}</pre>`
      );

      setJobId(data.jobId); // Store the job ID
      setJobSubmitted(true); // Mark the job as submitted successfully
    } catch (error) {
      setResponseOutput(`<strong>Error:</strong> ${error.message}`);
      setJobSubmitted(false); // Ensure jobSubmitted is false if there is an error
    }
  };

  return (
    <div className="container">

    <div id="exec-header">
      <h3>Submit Job</h3>
    </div>

    <hr />

      <form onSubmit={handleSubmit} id="execForm">
        <div className="form-group">
          <label htmlFor="authConfig">Auth Config</label>
          <select
            id="authConfig"
            required
            value={authConfig}
            onChange={(e) => setAuthConfig(e.target.value)}
          >
            <option value="" disabled>
              Select Auth Config
            </option>
            {authConfigs.map((config) => (
              <option key={config} value={config}>
                {config}
              </option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label htmlFor="workflow">Workflow</label>
          <select
            id="workflow"
            required
            value={workflow}
            onChange={(e) => setWorkflow(e.target.value)}
          >
            <option value="" disabled>
              Select Workflow
            </option>
            {workflows.map((workflowItem) => (
              <option key={workflowItem} value={workflowItem}>
                {workflowItem}
              </option>
            ))}
          </select>
        </div>

        <div className="form-group toggle-switch-group">
  <label htmlFor="as_json" className="toggle-switch">
    <input
      type="checkbox"
      id="as_json"
      checked={asJson}
      onChange={() => setAsJson(!asJson)}
    />
    <span className="slider"></span>
  </label>
  <span className="toggle-label">Format Output as JSON</span>
</div>


        <button className="submit" type="submit">
          Submit Job
        </button>
      </form>

      {jobSubmitted && (
        <div>
          <div
            id="responseOutput"
            className="output"
            dangerouslySetInnerHTML={{ __html: responseOutput }}
          />

          <div className="job-link-container">
            <p>
              <a
                href={`/jobs/${jobId}`}
                className="view-job-link"
                target="_blank"
                rel="noopener noreferrer"
              >
                View Job Details <FaExternalLinkAlt />
              </a>
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

export default Execute;
