// ServiceStatusModal.js
import React from "react";
import PropTypes from "prop-types";
import "./ServiceStatusModal.css"; // Create appropriate styles

const ServiceStatusModal = ({ isOpen, onClose, serviceName, output, error }) => {
  if (!isOpen) return null;

  return (
    <div className="modal-overlay" role="dialog" aria-modal="true">
      <div className="modal-content">
        <button className="modal-close-button" onClick={onClose} aria-label="Close Modal">
          &times;
        </button>
        <h2>Service Status: {serviceName}</h2>
        <div className="modal-body">
          <h3>Output:</h3>
          <pre className="modal-pre">{output || "No output available."}</pre>
          <h3>Error:</h3>
          <pre className="modal-pre">{error || "No error messages."}</pre>
        </div>
      </div>
    </div>
  );
};

ServiceStatusModal.propTypes = {
  isOpen: PropTypes.bool.isRequired,
  onClose: PropTypes.func.isRequired,
  serviceName: PropTypes.string,
  output: PropTypes.string,
  error: PropTypes.string,
};

export default ServiceStatusModal;