

import React, { useEffect, useState } from "react";
import { endpoint } from "../Config";
import { FaExternalLinkAlt, FaSyncAlt } from "react-icons/fa";
import "./Jobs.css";
import { GreenCheck, GreyDots } from "./StatusIcons";

const Jobs = () => {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    fetchJobs();
  }, []);

  const fetchJobs = async () => {
    setLoading(true);
    setError(null);

    try {
      const response = await fetch(`${endpoint}/job-status`, {
        method: "POST",
      });

      if (!response.ok) {
        throw new Error("Error fetching jobs. Please try again later.");
      }

      const data = await response.json();
      const jobsWithStatus = data.job_status.map((job) => ({
        ...job,
        showResult: false,
      }));

      setTimeout(() => {
        setJobs(jobsWithStatus);
        setLoading(false); // Hide loading and show the job list after 2 seconds
      }, 500);
    } catch (error) {
      setError(error.message);
      setLoading(false); // Ensure loading is stopped if there's an error
    }
  };

  const stopJob = async (jobId) => {
    try {
      const response = await fetch(`${endpoint}/stop-job`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ jobId }),
      });

      if (!response.ok) {
        throw new Error("Failed to stop the job.");
      }

      const updatedJobs = jobs.map((job) =>
        job.job === jobId ? { ...job, status: "Stopped" } : job
      );

      setJobs(updatedJobs);
    } catch (error) {
      setError("Could not stop the job. Please try again later.");
    }
  };

  const copyToClipboard = (output) => {
    navigator.clipboard.writeText(output).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 1500);
    });
  };

  return (
    <div className="container">
      <div id="jobs-header">
        <h3>Jobs Management</h3>
      </div>
      <hr />
      {loading && <p>Loading jobs...</p>}
      {error && <p className="error-message">{error}</p>}
      {!loading && (
        <div id="jobs-container">
          <table id="job-table">
            <thead>
              <tr>
                <th>Actions</th>
                <th>Job ID</th>
                <th>Workflow File</th>
                <th>Status</th>
                <th>Timestamp</th>
              </tr>
            </thead>
            <tbody>
              {jobs.length > 0 ? (
                jobs.map((job) => (
                  <tr key={job.job}>
                    <td>
                      {job.status === "Running" ? (
                        <button
                          className="stop-job-btn"
                          onClick={() => stopJob(job.job)}
                        >
                          Stop Job
                        </button>
                      ) : (
                        <button
                          className="view-details-btn"
                          onClick={() =>
                            window.open(`/jobs/${job.job}`, "_blank")
                          }
                        >
                          View <FaExternalLinkAlt />
                        </button>
                      )}
                    </td>
                    <td>{job.job}</td>
                    <td>{job.workflow}</td>
                    <td>
                      <div className="status-container">
                        {job.status === "Completed" ? (
                          <GreenCheck />
                        ) : (
                          <GreyDots />
                        )}
                        <span className="status-text">{job.status}</span>
                      </div>
                    </td>
                    <td>{job.timestamp}</td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="5">No jobs available</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      )}
      <button className="refresh-btn" onClick={fetchJobs}>
        <FaSyncAlt />
      </button>
    </div>
  );
};

export default Jobs;
